        XCTAssertTrue(result.content.contains("Center"), "expected to contain: \("Center")")
        XCTAssertTrue(result.content.contains("Right"), "expected to contain: \("Right")")
        XCTAssertTrue(result.content.contains("L"), "expected to contain: \("L")")
        XCTAssertTrue(result.content.contains("C"), "expected to contain: \("C")")
        XCTAssertTrue(result.content.contains("R"), "expected to contain: \("R")")
        XCTAssertTrue(result.content.contains("|"), "expected to contain: \("|")")
    }

    func testTableWithColspan() throws {
        // Table with colspan attribute in a header cell
        let result = try convert("<table><thead><tr><th colspan=\"2\">Full Name</th></tr></thead><tbody><tr><td>John</td><td>Doe</td></tr></tbody></table>")
        XCTAssertFalse(result.content.isEmpty, "expected non-empty value")
        XCTAssertTrue(result.content.contains("Full Name"), "expected to contain: \("Full Name")")
        XCTAssertTrue(result.content.contains("John"), "expected to contain: \("John")")
        XCTAssertTrue(result.content.contains("Doe"), "expected to contain: \("Doe")")
    }

    func testUnorderedList() throws {
        // Unordered list
        let result = try convert("<ul><li>Item 1</li><li>Item 2</li><li>Item 3</li></ul>")
        XCTAssertTrue(result.content.contains("- Item 1"), "expected to contain: \("- Item 1")")
        XCTAssertTrue(result.content.contains("- Item 2"), "expected to contain: \("- Item 2")")
        XCTAssertTrue(result.content.contains("- Item 3"), "expected to contain: \("- Item 3")")
    }

}
